#!/usr/bin/env powershell\n<#\n.SYNOPSIS\n    Backup Execution Engine database and configuration\n\n.DESCRIPTION\n    Creates timestamped backups of the database, configuration, and logs.\n    Maintains backup history.\n\n.PARAMETER BackupDir\n    Backup destination directory (default: backups/)\n\n.PARAMETER Retention\n    Days to retain backups (default: 30)\n\n.EXAMPLE\n    .\\backup.ps1\n    .\\backup.ps1 -BackupDir D:\\backups -Retention 60\n#>\n\nparam(\n    [string]$BackupDir = \"backups\",\n    [int]$Retention = 30\n)\n\n$timestamp = Get-Date -Format \"yyyyMMdd_HHmmss\"\n$backupPath = Join-Path $BackupDir $timestamp\n\n# Create backup directory\nNew-Item -ItemType Directory -Force -Path $backupPath | Out-Null\n\nWrite-Host \"Backing up to: $backupPath\"\n\n# Backup database\nif (Test-Path data/engine.db) {\n    Copy-Item data/engine.db \"$backupPath/engine.db\"\n    Write-Host \"✓ Database backed up\"\n}\n\n# Backup WAL files\nif (Test-Path data/engine.db-wal) {\n    Copy-Item data/engine.db-wal \"$backupPath/engine.db-wal\"\n}\nif (Test-Path data/engine.db-shm) {\n    Copy-Item data/engine.db-shm \"$backupPath/engine.db-shm\"\n}\n\n# Backup configuration\nCopy-Item .env \"$backupPath/.env.backup\" -Force\nWrite-Host \"✓ Configuration backed up\"\n\n# Backup recent logs\nif (Test-Path logs) {\n    $logsZip = \"$backupPath/logs.zip\"\n    Compress-Archive -Path logs/* -DestinationPath $logsZip -Force\n    Write-Host \"✓ Logs archived\"\n}\n\n# Cleanup old backups\n$oldBackups = Get-ChildItem $BackupDir -Directory | `\n    Where-Object { (Get-Date) - $_.LastWriteTime -gt (New-TimeSpan -Days $Retention) }\n\nif ($oldBackups) {\n    Write-Host \"Removing backups older than $Retention days:\"\n    $oldBackups | ForEach-Object {\n        Write-Host \"  Removing: $($_.Name)\"\n        Remove-Item $_ -Recurse -Force\n    }\n}\n\nWrite-Host \"\"\nWrite-Host \"✓ Backup complete!\"\nWrite-Host \"Location: $backupPath\"\nWrite-Host \"Size: $('{0:N2}' -f ((Get-ChildItem $backupPath -Recurse | Measure-Object -Property Length -Sum).Sum / 1MB)) MB\"\n